443: absl::optional<std::reference_wrapper<const absl::string_view>>
444: HeaderUtility::requestHeadersValid(const RequestHeaderMap& headers) {
445:   // Make sure the host is valid.
446:   if (headers.Host() && !HeaderUtility::authorityIsValid(headers.Host()->value().getStringView())) {
447:     return SharedResponseCodeDetails::get().InvalidAuthority;
448:   }
449:   if (headers.Method()) {
450:     absl::string_view method = headers.Method()->value().getStringView();
451:     if (method.empty() || std::any_of(method.begin(), method.end(), isInvalidToken)) {
452:       return SharedResponseCodeDetails::get().InvalidMethod;
453:     }
454:   }
455:   if (headers.Scheme() && absl::StrContains(headers.Scheme()->value().getStringView(), ",")) {
456:     return SharedResponseCodeDetails::get().InvalidScheme;
457:   }
458:   return absl::nullopt;
459: }
