379: ValidationResult
380: Http1HeaderValidator::validateResponseHeaders(const ::Envoy::Http::ResponseHeaderMap& header_map) {
381:   // Step 1: verify that required pseudo headers are present
382:   //
383:   // For HTTP/1.1 responses, RFC 9112 states that only the :status
384:   // header is required, https://www.rfc-editor.org/rfc/rfc9112.html#section-4:
385:   //
386:   // status-line = HTTP-version SP status-code SP [ reason-phrase ] CRLF
387:   // status-code = 3DIGIT
388:   const auto status = header_map.getStatusValue();
389:   if (status.empty()) {
390:     return {ValidationResult::Action::Reject, UhvResponseCodeDetail::get().InvalidStatus};
391:   }
392: 
393:   // Step 2: Validate Transfer-Encoding
394:   const auto transfer_encoding = header_map.getTransferEncodingValue();
395:   if (!transfer_encoding.empty() && (status[0] == '1' || status == "204")) {
396:     // From RFC 9112, https://www.rfc-editor.org/rfc/rfc9112.html#section-6.1:
397:     //
398:     // A server MUST NOT send a Transfer-Encoding header field in any response with a status code
399:     // of 1xx (Informational) or 204 (No Content).
400:     return {ValidationResult::Action::Reject,
401:             Http1ResponseCodeDetail::get().TransferEncodingNotAllowed};
402:   }
403: 
404:   ValidationResult result = validateContentLengthAndTransferEncoding(header_map);
405:   if (!result.ok()) {
406:     return result;
407:   }
408: 
409:   // Step 3: Verify each response header
410:   std::string reject_details;
411:   header_map.iterate([this, &reject_details](const ::Envoy::Http::HeaderEntry& header_entry)
412:                          -> ::Envoy::Http::HeaderMap::Iterate {
413:     const auto& header_name = header_entry.key();
414:     const auto& header_value = header_entry.value();
415: 
416:     auto entry_result = validateResponseHeaderEntry(header_name, header_value);
417:     if (!entry_result.ok()) {
418:       reject_details = static_cast<std::string>(entry_result.details());
419:     }
420: 
421:     return entry_result.ok() ? ::Envoy::Http::HeaderMap::Iterate::Continue
422:                              : ::Envoy::Http::HeaderMap::Iterate::Break;
423:   });
424: 
425:   if (!reject_details.empty()) {
426:     return {ValidationResult::Action::Reject, reject_details};
427:   }
428: 
429:   return ValidationResult::success();
430: }
