432: HeaderValidator::HeaderValueValidationResult
433: Http1HeaderValidator::validateTransferEncodingHeader(const HeaderString& value) const {
434:   // HTTP/1.1 states that requests with an unrecognized transfer encoding should
435:   // be rejected, from RFC 9112, https://www.rfc-editor.org/rfc/rfc9112.html#section-6.1:
436:   //
437:   // A server that receives a request message with a transfer coding it does not understand SHOULD
438:   // respond with 501 (Not Implemented).
439:   //
440:   // This method implements the existing (pre-UHV) Envoy behavior of only allowing a "chunked"
441:   // Transfer-Encoding.
442:   const auto encoding = value.getStringView();
443: 
444:   if (!encoding.empty() &&
445:       !absl::EqualsIgnoreCase(encoding, header_values_.TransferEncodingValues.Chunked)) {
446:     return {HeaderValueValidationResult::Action::Reject,
447:             Http1ResponseCodeDetail::get().InvalidTransferEncoding};
448:   }
449: 
450:   return HeaderValueValidationResult::success();
451: }
